+    #[test]
+    fn fnv1a64_bytes_long_input() {
+        // Test the 8-byte unrolled loop path
+        let data: Vec<u8> = (0..32).collect();
+        let hash = fnv1a64_bytes(FNV_OFFSET_BASIS, &data);
+        let hash2 = fnv1a64_bytes(FNV_OFFSET_BASIS, &data);
